            if (isInspectMode) {
              e.preventDefault();
              e.stopPropagation();
              const el = e.target;
              window.parent.postMessage({
                type: 'INSPECT_ELEMENT',
                element: {
                  tagName: el.tagName,
                  innerText: el.innerText.slice(0, 50),
                  className: el.className,
                  id: el.id
                }
              }, '*');
            }
